11	  .subtitle { color: #999; font-size: 0.78em; margin-bottom: 14px; }
12	  .summary-bar { display: flex; gap: 14px; margin-bottom: 10px; font-size: 0.8em; align-items: center; }
13	
14	  /* Matrix */
15	  .matrix { display: grid; gap: 1px; background: #e0e0e0; border-radius: 10px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,.04); }
16	  .cell { background: #fff; padding: 6px; min-height: 48px; display: flex; flex-wrap: wrap; gap: 3px; align-content: start; }
