19	
20	  .customer-chip { display: inline-flex; align-items: center; gap: 3px; padding: 2px 7px; border-radius: 12px; font-size: 0.71em; cursor: pointer; border: 1px solid transparent; white-space: nowrap; transition: all .12s; }
21	  .customer-chip:hover { transform: translateY(-1px); box-shadow: 0 2px 6px rgba(0,0,0,.1); }
22	  .chip-red { background: #ffebee; border-color: #ffcdd2; color: #b71c1c; }
23	  .chip-yellow { background: #fff8e1; border-color: #ffecb3; color: #e65100; }
24	  .chip-grey { background: #f5f5f5; border-color: #eee; color: #888; }
25	  .chip-dot { width: 5px; height: 5px; border-radius: 50%; flex-shrink: 0; }
26	  .chip-dot-red { background: #d32f2f; }
27	  .chip-dot-yellow { background: #f57c00; }
28	  .chip-dot-grey { background: #bbb; }
29	  .chip-badge { font-size: 0.66em; padding: 1px 3px; border-radius: 6px; background: rgba(0,0,0,.06); }
30	
31	  /* Overlay */
32	  .overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,.35); z-index: 100; justify-content: center; align-items: center; }
33	  .overlay.show { display: flex; }
34	
35	  /* Modal */
36	  .modal { background: #fff; border-radius: 14px; box-shadow: 0 8px 40px rgba(0,0,0,.18); width: 680px; max-height: 85vh; display: flex; flex-direction: column; overflow: hidden; animation: modalIn .2s ease; }
37	  @keyframes modalIn { from { opacity:0; transform:scale(.95) translateY(10px); } to { opacity:1; transform:scale(1) translateY(0); } }
38	  .modal-header { padding: 18px 24px; border-bottom: 1px solid #f0f0f0; display: flex; justify-content: space-between; align-items: center; flex-shrink: 0; }
39	  .modal-header h2 { font-size: 1.1em; }
40	  .modal-close { background: none; border: none; font-size: 1.3em; cursor: pointer; color: #999; padding: 6px; border-radius: 6px; }
41	  .modal-close:hover { background: #f5f5f5; }
42	  .modal-body { padding: 20px 24px; overflow-y: auto; flex: 1; font-size: 0.86em; }
43	  .modal-footer { padding: 14px 24px; border-top: 1px solid #f0f0f0; display: flex; gap: 8px; flex-shrink: 0; }
44	
45	  .btn { padding: 7px 18px; border-radius: 6px; border: 1px solid #ddd; font-size: 0.82em; cursor: pointer; background: #fff; transition: .12s; }
46	  .btn:hover { background: #f5f5f5; }
47	  .btn-primary { background: #1976d2; color: #fff; border-color: #1976d2; }
48	  .btn-primary:hover { background: #1565c0; }
49	
50	  .fm-grid { display: grid; grid-template-columns: 1fr 1fr 1fr 1fr; gap: 10px; margin-bottom: 18px; }
51	  .fm-item { background: #fafafa; border-radius: 8px; padding: 8px 12px; }
52	  .fm-label { color: #999; font-size: 0.72em; text-transform: uppercase; letter-spacing: 0.5px; }
53	  .fm-value { font-weight: 600; font-size: 0.95em; margin-top: 2px; }
54	
55	  .section { margin-bottom: 14px; }
56	  .section-title { font-weight: 600; font-size: 0.8em; color: #888; margin-bottom: 8px; display: flex; align-items: center; gap: 6px; text-transform: uppercase; letter-spacing: 0.5px; }
57	
58	  .driver-list { display: flex; flex-direction: column; gap: 6px; }
