61	  .driver-item-yellow { background: #fffdf5; border: 1px solid #ffecb3; }
62	  .driver-icon { font-size: 1.1em; flex-shrink: 0; margin-top: 1px; }
63	
64	  .chat-snippet { background: #fafafa; border-radius: 8px; padding: 10px 14px; font-size: 0.84em; }
65	  .chat-line { padding: 3px 0; display: flex; gap: 8px; align-items: baseline; }
66	  .chat-who { font-weight: 600; flex-shrink: 0; min-width: 22px; }
