  .key-num { background: #f5f5f5; border-radius: 6px; padding: 7px 10px; margin-bottom: 3px; font-size: 0.84em; }
  .info-note { background: #fff9c4; border-radius: 6px; padding: 8px 12px; font-size: 0.8em; color: #666; }
</style>
