    const nameFromFile = file.replace(/^[\d-]+_/, "").replace(/\.md$/, "");
    const name = h1Match ? h1Match[1].trim() : nameFromFile;

    // 最后联系天数
    const contact = contactMap[fm.cid];
    const daysSinceLastContact = contact?.daysSinceLastContact ?? null;

    // 最后联系显示
    let lastContactDisplay = "?";
    if (daysSinceLastContact !== null) {
      if (daysSinceLastContact === 0) lastContactDisplay = "今天";
      else if (daysSinceLastContact === 1) lastContactDisplay = "昨天";
      else if (daysSinceLastContact < 30) lastContactDisplay = `${daysSinceLastContact}天前`;
      else lastContactDisplay = `${Math.round(daysSinceLastContact / 30)}月前`;
    }

    const talkSummary = extractTalkSummary(content);
    const nextStep = extractNextStep(content);

