      country: fm.country || "?",
      heat: fm.heat || "COLD",
      stage: fm.stage || "未知",
      lastContact: lastContactDisplay,
      daysSinceLastContact: daysSinceLastContact ?? 999,
      talkSummary,
      nextStep,
      cid: fm.cid,
      file,
      checked: fm.checked || "?",
