      const cls = fd.level==='red'?'driver-item-red':'driver-item-yellow';
      const icon = fd.level==='red'?'🔴':'🟡';
      html += '<div class="driver-item '+cls+'"><span class="driver-icon">'+icon+'</span><div><strong>'+esc(fd.title)+'</strong><div style="color:#999;font-size:0.85em;margin-top:2px;">'+esc(fd.detail)+'</div></div></div>';
    }
    html += '</div></div>';
  } else {
    html += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">无活跃因子。该客户在正常流转中。</div></div>';
  }

  // Chat / key numbers from brief
  if (c.hasBrief) {
    if (c.talkSummary) {
      html += '<div class="section"><div class="section-title">💬 聊到哪了</div><div class="chat-snippet">'+esc(c.talkSummary)+'</div></div>';
    }
    if (c.keyNums && c.keyNums.length) {
      html += '<div class="section"><div class="section-title">🔢 关键数字</div>';
      for (const n of c.keyNums) html += '<div class="key-num">'+esc(n)+'</div>';
      html += '</div>';
    }
    if (c.nextStep) {
      html += '<div class="section"><div class="section-title">→ 下一步</div><div style="font-size:0.88em;line-height:1.6;white-space:pre-line">'+esc(c.nextStep)+'</div></div>';
    }
  } else {
    html += '<div class="info-note">📝 暂无状态卡。运行 /okki 深度分析创建。</div>';
  }

  html += '</div>';
  html += '<div class="modal-footer">路径: ' + (c.briefFile || '未建卡') + ' | 数据源: factor_baselines + soon_layer_cards</div>';

  document.getElementById('modal').innerHTML = html;
  document.getElementById('overlay').classList.add('show');
}

function factorDesc(f) {
  var base = (f.factor||'').split('(')[0].trim();
  var entry = FACTOR_DESC[base] || FACTOR_DESC[f.factor] || {title:f.factor,level:'yellow'};
  var detail = (f.days||'?')+'天前基线('+(f.baseline||'?')+')';
  if (f.rhythmDay) detail += '，节奏第'+f.rhythmDay+'天';
  if (f.observeMode) detail = '观察模式 | '+detail;
  if (f.priority==='high') detail = '⚠ 高优先级 | '+detail;
  return {title:entry.title, level:entry.level, detail:detail};
}

function closeModal() {
