转：折叠显示","+      if (u.key === "grey") {","+        const show = bucket.slice(0, 3);","+        const rest = bucket.length - 3;","+        const chips = show.map((c) => `<span class="customer-chip chip-grey" onclick="openModal('${esc(c.cid)}')">${esc(c.name)}</span>`).join("");","+        const more = rest > 0 ? `<span class="customer-chip chip-grey">+${rest}</span>` : "";","+        html += `  <div class="cell">${chips}${more}</div>\n`;","+        continue;","+      }","+","+      // RED / YELLOW：展示所有芯片","+      const chipClass = u.key === "red" ? "chip-red" : "chip-yellow";","+      const chips = bucket.map((c) => {","+        const badge = c.factors.length > 0 ? shortBadge(c.factors[0]) : "";","+        const tierMark = (c.tier === "S" || c.tier === "A") ? `<span class="chip-tier-${c.tier.toLowerCase()}">${c.tier}</span>` : "";","+        return `<span class="customer-chip ${chipClass}" onclick="openModal('${esc(c.cid)}')"><span class="chip-dot ${dotClass}"></span>${esc(c.name)}${tierMark}${badge}</span>`;","+      }).join("\n    ");","+      html += `  <div class="cell">${chips}</div>\n`;","+    }","+  }","+","+  html += `</div>","+<!-- Overlay -->","+<div class="overlay" id="overlay" onclick="if(event.target===this)closeModal()">","+<div class="modal" id="modal"></div>","+</div>","+","+<script>","+const CARDS = ${JSON.stringify(cards, null, 0)};","+const COUNTRY_CN = ${JSON.stringify(COUNTRY_CN)};","+const COLUMNS = ${JSON.stringify(COLUMNS)};","+const FACTOR_DESC = ${JSON.stringify(FACTOR_DESC)};","+","+function openModal(cid) {","+  const c = CARDS.find(x => x.cid === cid);","+  if (!c) return;","+  let html = '';","+  html += '<div class="modal-header"><h2>' + esc(c.name) + '</h2><button class="modal-close" onclick="closeModal()">✕</button></div>';","+  html += '<div class="modal-body">';","+","+  // Frontmatter","+  html += '<div class="fm-grid">';","+  for (const [k,v] of [['国家',c.countryCN||c.country],['阶段',c.stage],['等级',c.tier+'级'],['最后联系',c.daysSince!==