 '未建卡') + ' | 数据源: factor_baselines + soon_layer_cards</div>';","+","+  document.getElementById('modal').innerHTML = html;","+  document.getElementById('overlay').classList.add('show');","+}","+","+function factorDesc(f) {","+  var base = (f.factor||'').split('(')[0].trim();","+  var entry = FACTOR_DESC[base] || FACTOR_DESC[f.factor] || {title:f.factor,level:'yellow'};","+  var detail = (f.days||'?')+'天前基线('+(f.baseline||'?')+')';","+  if (f.rhythmDay) detail += '，节奏第'+f.rhythmDay+'天';","+  if (f.observeMode) detail = '观察模式 | '+detail;","+  if (f.priority==='high') detail = '⚠ 高优先级 | '+detail;","+  return {title:entry.title, level:entry.level, detail:detail};","+}","+","+function closeModal() {","+  document.getElementById('overlay').classList.remove('show');","+}","+","+function esc(s) {","+  if (typeof s !== 'string') return s;","+  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');","+}","+","+document.addEventListener('keydown', e => { if (e.key==='Escape') closeModal(); });","+</script>","+","+</body>","+</html>`;","+","+  return html;","+}","+","+function shortBadge(f) {","+  const code = (f.factor || "").split("(")[0].trim();","+  const map = {","+    "S1 该深挖需求了": "深挖", "S2 该追问了": "追问", "S3 该推进了": "推进",","+    "S4 该催款了": "催款", "S5a 该更新进度了": "进度", "S6 该更新物流了": "物流",","+    "S7a 该回访了": "回访", "S7b 该推返单了": "返单", "S8 该收尾了": "收尾", "S9 该接触了": "接触",","+  };","+  const tag = map[code] || "待办";","+  return `<span class="chip-badge">${tag}</span>`;","+}","+","+function esc(s) {","+  if (typeof s !== "string") return String(s);","+  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");","+}","+","+// ═══════════════════════════════════════════════════════","+// Markdown 表格（兼容旧模式）","+// ═══════════════════════════════════════════════════════","+","+function renderMarkdown(cards) {","+  const active = cards.filter((c) => c.urgencyKey !== "frozen");","+  const counts = { red: 0, yellow: 0, grey: 0, frozen: 0 };","+  for (const c of cards) counts[c.urgencyKey] = (counts[c.urgencyKey] || 0) + 1;","+","+  let md = `# OKKI 客户看板\n\n`;","+  md += `> ${TODAY} | 🔴需立即处理:${counts.red} 🟡需定时关注:${counts.yellow} ⚪正常:${counts.grey} ❄️冷冻:${counts.frozen}\n\n`;","+  md += `| 客户 | 国家 | 等级 | 阶段 | 最后联系 | 驱动因子 | 下一步 |\n`;","+  md += `|------|------|:---:|------|----------|----------|--------|\n`;","+","+  const order = ["red", "yellow", "grey"];","+  let lastU = "";","+  for (const u of order) {","+    for (const c of active) {","+      if (c.urgencyKey !== u) continue;","+      if (c.urgencyKey !== lastU) {","+        lastU = c.urgencyKey;","+        const label = URGENCY[u.toUpperCase()] ? URGENCY[u.toUpperCase()].label : u;","+        md += `| **── ${label} ──** | | | | | | |\n`;","+      }","+      const factorNames = c.factors.map((f) => (f.factor || "").split("(")[0].trim().replace("S1 ", "").replace("S3 ", "").replace("S4 ", "").replace("S5a ", "")).join(" · ") || "—";","+      const daysStr = c.daysSince !== null ? `${c.daysSince}天前` : "?";","+      md += `| ${c.name} | ${c.countryCN} | ${c.tier} | ${c.stage} | ${daysStr} | ${factorNames} | ${c.nextStep || "—"} |\n`;","+    }","+  }","+  return md;","+}","+","+// ═══════════════════════════════════════════════════════","+// 旧版 HTML 表格（--html 兼容）","+// ═══════════════════════════════════════════════════════","+","+function renderHTMLTable(cards) {","+  const active = cards.filter((c) => c.urgencyKey !== "frozen");","+  const heatIcon = { red: "🔴", yellow: "🟡", grey: "⚪" };","+","+  let html = `<!DOCTYPE html>","+<html lang="zh-CN">","+<head><meta charset="UTF-8"><title>OKKI 客户看板 — ${TODAY}</title>","+<style>","+  body { font-family: -apple-system, sans-serif; margin: 20px; color: #333; }","+  table { border-collapse: collapse; width: 100%; font-size: 0.9em; }","+  th { background: #f5f5f5; padding: 10px 8px; text-align: left; border-bottom: 2px solid #ddd; }","+  td { padding: 8px; border-bottom: 1px solid #eee; vertical-align: top; }","+  .heat-red { color: #d32f2f; font-weight: bold; }","+  .heat-yellow { color: #f57c00; }","+  .heat-grey { color: #999; }","+  .section-row td { background: #f0f0f0; font-weight: bold; padding: 6px 8px; font-size: 0.85em; }","+</style></head><body>","+<h1>OKKI 客户看板</h1>","+<p>${TODAY}</p>","+<table><thead><tr><th>客户</th><th>国家</th><th>等级</th><th>阶段</th><th>最后联系</th><th>驱动因子</th><th>下一步</th></tr></thead><tbody>`;","+","+  let lastU = "";","+  for (const c of active) {","+    if (c.urgencyKey !== lastU) {","+      lastU = c.urgencyKey;","+      html += `<tr class="section-row"><td colspan="7">── ${URGENCY[c.urgencyKey.toUpperCase()]?.label || c.urgencyKey} ──</td></tr>\n`;","+    }","+    const cls = `heat-${c.urgencyKey}`;","+    const factors = c.factors.map((f) => (f.factor || "").split("(")[0].trim()).join(" · ") || "—";","     html += `<tr>","-  <td>${r.name}</td>","-  <td>${r.country}</td>","-  <td class="${heatClass}">${heatIcon(r.heat)} ${r.heat}</td>","-  <td>${r.stage}</td>","-  <td>${r.lastContact}</td>","-  <td class="summary" title="${summary}">${summary}</td>","-  <td class="step" title="${step}">${step}</td>","-</tr>\n`;","+  <td>${esc(c.name)}</td><td>${c.countryCN}</td><td>${c.tier}</td><td>${c.stage}</td>","+  <td>${c.daysSince !== null ? c.daysSince + "天前" : "?"}</td>","+  <td>${esc(factors)}</td><td>${esc(c.nextStep || "—")}</td></tr>\n`;","   }"," ","   html += `</tbody></table></body></html>`;","   return html;"," }"," ","-// ── 执行 ──────────────────────────────────────────────────","+// ═══════════════════════════════════════════════════════","+// 写入 + 运行统计","+// ═══════════════════════════════════════════════════════"," ","-const rows = buildDashboard();","+function main() {","+  const cards = buildCustomerCards();","+  if (!cards) process.exit(1);"," ","-if (rows.length === 0) {","-  console.log("无状态卡数据。请先运行 batch_gen_briefs.js");","-  process.exit(1);","-}","+  const counts = { red: 0, yellow: 0, grey: 0, frozen: 0 };","+  for (const c of cards) counts[c.urgencyKey] = (counts[c.urgencyKey] || 0) + 1;"," ","-const output = htmlMode ? renderHTML(rows) : renderMarkdown(rows);","+  let output;","+  if (mdMode) {","+    output = renderMarkdown(cards);","+  } else if (htmlTableMode) {","+    output = renderHTMLTable(cards);","+  } else {","+    output = renderMatrixHTML(cards);","+  }"," ","-if (outFile) {","-  fs.writeFileSync(outFile, output, "utf-8");","-  console.log(`看板已保存: ${outFile}`);","-} else {","-  console.log(output);","+  const dest = outFile || (mdMode || htmlTableMode ? null : path.join(OUTPUT_DIR, "dashboard.html"));","+","+  if (dest) {","+    fs.writeFileSync(dest, output, "utf-8");","+    console.log(`✅ 看板已生成: ${dest}`);","+  } else {","+    console.log(output);","+  }","+","+  console.error(`\n── OKKI 看板 ${TODAY} ──`);","+  console.error(`🔴 需立即处理: ${counts.red}人`);","+  console.error(`🟡 需定时关注: ${counts.yellow}人`);","+  console.error(`⚪ 正常流转:   ${counts.grey}人`);","+  console.error(`❄️ 冷冻:       ${counts.frozen}人`);","+  console.error(`📊 总计:       ${cards.length}人`);"," }","+","+main();"]}],"originalFile":"#!/usr/bin/env node
/**
 * gen_dashboard.js — 从状态卡生成看板表格
 *
 * 读取 data/briefs/*.md，生成分组排序的客户看板。
 *
 * 用法:
 *   node scripts/gen_dashboard.js              → Markdown 表格到 stdout
 *   node scripts/gen_dashboard.js --html       → HTML 到 stdout
 *   node scripts/gen_dashboard.js -o board.md  → 输出到文件
 */

const fs = require("fs");
const path = require("path");

const DATA_DIR = path.resolve(__dirname, "..", "data");
const BRIEFS_DIR = path.join(DATA_DIR, "briefs");
const LATEST_PATH = path.join(DATA_DIR, "tm_conversations_latest.json");

const args = process.argv.slice(2);
const htmlMode = args.includes("--html");
const outFile = (() => {
  const idx = args.indexOf("-o");
  return idx >= 0 ? args[idx + 1] : null;
})();

// ── 解析 frontmatter ─────────────────────────────────────
function parseFrontmatter(content) {
  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
  if (!match) return {};
  const fm = {};
  for (const line of match[1].split("\n")) {
    const kv = line.match(/^(\w+):\s*(.+)$/);
    if (kv) fm[kv[1]] = kv[2].trim();
  }
  return fm;
}

// ── 从状态卡正文提取字段 ─────────────────────────────────

function extractSection(content, heading) {
  const re = new RegExp(`## ${heading}\\s*\\n([\\s\\S]*?)(?=\\n## |$)`, "i");
  const match = content.match(re);
  return match ? match[1].trim() : "";
}

function extractTalkSummary(content) {
  // 从"最近动态"中提取最后一句话（→ 前面的摘要）
  const section = extractSection(content, "最近动态");
  // 取 → 前面的最后一行有意义文本
  const lines = section.split("\n").filter((l) => l.trim() && !l.startsWith("[初稿]") && !l.startsWith("→"));
  if (lines.length > 0) {
    const last = lines[lines.length - 1];
    // 清理日期前缀和 MsgID
    const cleaned = last.replace(/^-\s*\d{4}-\d{2}-\d{2}\s*(我|客):\s*/, "").replace(/（MsgID:[\w.]+）$/, "");
    return cleaned.substring(0, 80);
  }
  // fallback: return the → line content
  const arrowLine = section.match(/→\s*(.+)/);
  return arrowLine ? arrowLine[1].substring(0, 80) : "";
}

function extractNextStep(content) {
  const section = extractSection(content, "下一步");
  const arrowLine = section.match(/→(?:\s*\[初稿\]\s*)?(.+)/);
  return arrowLine ? arrowLine[1].trim().substring(0, 60) : section.substring(0, 60);
}

function extractFirstContact(content) {
  const section = extractSection(content, "画像");
  const match = section.match(/(\d{4}-\d{2}-\d{2})\s*首次联系/);
  return match ? match[1] : null;
}

// ── 获取最后联系时间（从 tm_conversations_latest.json） ──
function loadContactTimes() {
  if (!fs.existsSync(LATEST_PATH)) return {};
  const data = JSON.parse(fs.readFileSync(LATEST_PATH, "utf-8"));
  const map = {};
  for (const conv of data.conversations || []) {
    map[conv.cid] = {
      lastContactTime: conv.lastContactTime,
      daysSinceLastContact: conv.preComputed?.daysSinceLastContact ?? null,
    };
  }
  return map;
}

// ── 主逻辑 ──────────────────────────────────────────────────

function buildDashboard() {
  if (!fs.existsSync(BRIEFS_DIR)) {
    console.error("briefs 目录不存在");
    return [];
  }

  const contactMap = loadContactTimes();
  const files = fs.readdirSync(BRIEFS_DIR).filter((f) => f.endsWith(".md"));
  const rows = [];

  for (const file of files) {
    const content = fs.readFileSync(path.join(BRIEFS_DIR, file), "utf-8");
    const fm = parseFrontmatter(content);
    if (!fm.cid) continue;

    // 客户名：从 H1 或文件名提取
    const h1Match = content.match(/^#\s+(.+)$/m);
    const nameFromFile = file.replace(/^[\d-]+_/, "").replace(/\.md$/, "");
    const name = h1Match ? h1Match[1].trim() : nameFromFile;

    // 最后联系天数
    const contact = contactMap[fm.cid];
    const daysSinceLastContact = contact?.daysSinceLastContact ?? null;

    // 最后联系显示
    let lastContactDisplay = "?";
    if (daysSinceLastContact !== null) {
      if (daysSinceLastContact === 0) lastContactDisplay = "今天";
      else if (daysSinceLastContact === 1) lastContactDisplay = "昨天";
      else if (daysSinceLastContact < 30) lastContactDisplay = `${daysSinceLastContact}天前`;
      else lastContactDisplay = `${Math.round(daysSinceLastContact / 30)}月前`;
    }

    const talkSummary = extractTalkSummary(content);
    const nextStep = extractNextStep(content);

    rows.push({
      name,
      country: fm.country || "?",
      heat: fm.heat || "COLD",
      stage: fm.stage || "未知",
      lastContact: lastContactDisplay,
      daysSinceLastContact: daysSinceLastContact ?? 999,
      talkSummary,
      nextStep,
      cid: fm.cid,
      file,
      checked: fm.checked || "?",
    });
  }

  // 排序：NOW → SOON → COLD，同热度内按最后联系时间升序
  const heatOrder = { NOW: 0, SOON: 1, COLD: 2 };
  rows.sort((a, b) => {
    const ha = heatOrder[a.heat] ?? 9;
    const hb = heatOrder[b.heat] ?? 9;
    if (ha !== hb) return ha - hb;
    return a.daysSinceLastContact - b.daysSinceLastContact;
  });

