  "S4 该催款了(观察)":   { title: "该催款(观察)——长期未付，观察模式", level: "yellow" },
  "S5a 该更新进度了":    { title: "该更新进度——备货/生产中，需同步进展给客户", level: "yellow" },
  "S6 该更新物流了":    { title: "该更新物流——货物在途，需跟踪并通知客户", level: "yellow" },
  "S7a 该回访了":       { title: "该回访——客户已签收，需回访满意度和复购意向", level: "yellow" },
  "S7b 该推返单了":     { title: "该推返单——签收后进入复购窗口，推新品", level: "yellow" },
  "S8 该收尾了":        { title: "该收尾——售后问题需跟进解决", level: "yellow" },
  "S9 该接触了":        { title: "该接触——待返单客户定期触达", level: "yellow" },
};

function factorDesc(f) {
  const base = (f.factor || "").split("(")[0].trim();
  const entry = FACTOR_DESC[base] || FACTOR_DESC[f.factor] || { title: f.factor, level: "yellow" };
  let detail = `${f.days || "?"}天前基线(${f.baseline || "?"})`;
  if (f.rhythmDay) detail += `，节奏第${f.rhythmDay}天`;
  if (f.observeMode) detail = `观察模式 | ${detail}`;
  if (f.priority === "high") detail = `⚠ 高优先级 | ${detail}`;
  return { ...entry, detail };
}

