  // Frontmatter
  html += '<div class="fm-grid">';
  for (const [k,v] of [['国家',c.countryCN||c.country],['阶段',c.stage],['等级',c.tier+'级'],['最后联系',c.daysSince!==null?c.daysSince+'天前':'?']]) {
    html += '<div class="fm-item"><div class="fm-label">'+k+'</div><div class="fm-value">'+esc(String(v))+'</div></div>';
  }
  if (c.firstContact) html += '<div class="fm-item"><div class="fm-label">首次联系</div><div class="fm-value">'+c.firstContact+'</div></div>';
