136	function loadJSON(filename) {
137	  const p = path.join(OUTPUT_DIR, filename);
138	  if (!fs.existsSync(p)) return null;
139	  return JSON.parse(fs.readFileSync(p, "utf-8"));
140	}
141	
142	function loadBriefs() {
143	  const map = {};
144	  if (!fs.existsSync(BRIEFS_DIR)) return map;
145	  for (const file of fs.readdirSync(BRIEFS_DIR)) {
146	    if (!file.endsWith(".md")) continue;
147	    const content = fs.readFileSync(path.join(BRIEFS_DIR, file), "utf-8");
148	    const fm = parseFrontmatter(content);
149	    if (fm.cid) map[fm.cid] = { frontmatter: fm, content, file };
150	  }
151	  return map;
152	}
153	
154	function parseFrontmatter(content) {
155	  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
156	  if (!match) return {};
157	  const fm = {};
158	  for (const line of match[1].split("\n")) {
159	    const kv = line.match(/^(\w+):\s*(.+)$/);
160	    if (kv) fm[kv[1]] = kv[2].trim();
161	  }
162	  return fm;
163	}
164	
165	function extractSection(content, heading) {
166	  const re = new RegExp(`## ${heading}\\s*\\n([\\s\\S]*?)(?=\\n## |$)`, "i");
167	  const m = content.match(re);
168	  return m ? m[1].trim() : "";
169	}
170	
171	function extractTalkSummary(content) {
172	  const section = extractSection(content, "最近动态");
173	  const lines = section.split("\n").filter((l) => l.trim() && !l.startsWith("[初稿]") && !l.startsWith("→"));
174	  if (lines.length > 0) {
175	    const last = lines[lines.length - 1];
176	    return last.replace(/^-\s*\d{4}-\d{2}-\d{2}\s*(我|客):\s*/, "").replace(/（MsgID:[\w.]+）$/, "").substring(0, 120);
177	  }
178	  return "";
179	}
180	
181	function extractNextStep(content) {
182	  const section = extractSection(content, "下一步");
183	  const m = section.match(/→(?:\s*\[初稿\]\s*)?(.+)/);
184	  return m ? m[1].trim() : section.substring(0, 80);
185	}
186	
187	function extractKeyNums(content) {
188	  const section = extractSection(content, "关键数字");
189	  if (!section) return [];
190	  return section.split("\n").filter((l) => l.trim().startsWith("-")).map((l) => l.replace(/^-\s*/, "").trim());
191	}
