197	function buildCustomerCards() {
198	  const baselines = loadJSON("factor_baselines.json");
199	  const soon = loadJSON("soon_layer_cards.json");
200	  const cold = loadJSON("cold_layer_stratification.json");
201	  const briefs = loadBriefs();
202	
203	  if (!baselines) {
204	    console.error("factor_baselines.json 不存在，请先运行 init_factor_baselines.js");
205	    return null;
206	  }
207	
208	  // 建立 SOON 因子查找表
209	  const factorMap = new Map();
210	  if (soon) {
211	    for (const c of soon.customers || []) {
212	      factorMap.set(c.cid, c);
213	    }
214	  }
215	
216	  // 建立冷层查找表
217	  const coldCids = new Set();
218	  if (cold) {
219	    for (const layer of Object.values(cold.frozen || {})) {
220	      for (const c of layer) coldCids.add(c.cid);
221	    }
222	  }
223	
224	  const cards = [];
225	
226	  for (const [cid, data] of Object.entries(baselines)) {
227	    const stage = data.stage || "未知";
228	    const soonData = factorMap.get(cid);
229	    const factors = soonData ? soonData.factors : [];
230	    const urgencyKey = coldCids.has(cid) ? "frozen" : classifyUrgency(factors);
231	    const urgency = URGENCY[urgencyKey.toUpperCase()] || URGENCY.GREY;
232	    const colKey = stageColKey(stage);
233	    const tier = (data.meta && data.meta.customer_tier) || "C";
234	
235	    // 计算最后联系天数 (从基线取最近日期)
236	    let daysSince = null;
237	    let lastContactDate = null;
238	    if (data.baselines) {
239	      let latest = null;
240	      for (const v of Object.values(data.baselines)) {
241	        if (v && (!latest || v > latest)) latest = v;
242	      }
243	      if (latest) {
244	        lastContactDate = latest;
245	        daysSince = Math.floor((new Date(TODAY) - new Date(latest)) / 86400000);
246	      }
247	    }
248	
249	    // 首次联系：取最早基线日期
250	    let firstContact = null;
251	    if (data.baselines) {
252	      let earliest = null;
253	      for (const v of Object.values(data.baselines)) {
254	        if (v && (!earliest || v < earliest)) earliest = v;
255	      }
256	      firstContact = earliest;
257	    }
258	
259	    // 从状态卡获取补充信息
260	    const brief = briefs[cid];
261	    let talkSummary = "", nextStep = "", keyNums = [];
262	    if (brief) {
263	      talkSummary = extractTalkSummary(brief.content);
264	      nextStep = extractNextStep(brief.content);
265	      keyNums = extractKeyNums(brief.content);
266	    }
267	
268	    cards.push({
269	      cid,
270	      name: data.name || "?",
271	      country: data.country || "?",
272	      countryCN: countryCN(data.country),
273	      stage,
274	      colKey,
275	      tier,
276	      urgencyKey,
277	      urgency,
278	      factors,
279	      daysSince,
280	      lastContactDate,
281	      firstContact,
282	      talkSummary,
283	      nextStep,
284	      keyNums,
285	      hasBrief: !!brief,
286	      briefFile: brief ? brief.file : null,
287	    });
288	  }
289	
290	  // 在"正常流转"行：折叠显示（仅保留前几个名字 + 计数）
291	  // 冷冻行同理
292	
293	  return cards;
294	}
