    case "S4 该催款了":
      if (isObserve) return "催款观察";
      return `催款${days}d`;
    case "S1 该深挖需求了":
      if (isDoudi) return `兜底${days}d`;
      return `深挖${days}d`;
    case "S2 该追问了":
      return `追问${days}d`;
    case "S5a 该更新进度了":
      if (isHigh) return "超期!";
      return `进度${days}d`;
    case "S6 该更新物流了":
      return "物流";
    case "S7a 该回访了":
      return "回访";
    case "S7b 该推返单了":
      return "返单";
    case "S8 该收尾了":
