/**
 * gen_dashboard.js — OKKI 矩阵看板 + 弹窗详情（v2 品质）
 *
 * 数据源:
 *   - output/factor_baselines.json   (全员阶段+基线+等级)
 *   - output/soon_layer_cards.json   (SOON 因子命中清单)
 *   - output/cold_layer_stratification.json (冷层/冷冻分层)
 *   - data/briefs/*.md              (状态卡，聊天/关键数字/下一步)
 *
 * 用法:
 *   node scripts/gen_dashboard.js                  → 矩阵 HTML → output/dashboard.html
 *   node scripts/gen_dashboard.js --md              → Markdown 表格 → stdout
 *   node scripts/gen_dashboard.js --html            → 旧版 HTML 表格 → stdout
 *   node scripts/gen_dashboard.js -o board.html     → 指定输出路径
 */

const fs = require("fs");
const path = require("path");

const ROOT = path.resolve(__dirname, "..");
const OUTPUT_DIR = path.join(ROOT, "output");
const BRIEFS_DIR = path.join(ROOT, "data", "briefs");
const TODAY = new Date().toISOString().slice(0, 10);

const args = process.argv.slice(2);
const mdMode = args.includes("--md");
const htmlTableMode = args.includes("--html");
const outFile = (() => {
  const idx = args.indexOf("-o");
  return idx >= 0 ? args[idx + 1] : null;
})();

// ═══════════════════════════════════════════════
// 国家代码 → 中文
// ═══════════════════════════════════════════════
const COUNTRY_CN = {
  US:"美国",GB:"英国",DE:"德国",FR:"法国",IT:"意大利",ES:"西班牙",NL:"荷兰",BE:"比利时",PT:"葡萄牙",RU:"俄罗斯",TR:"土耳其",
  IN:"印度",PK:"巴基斯坦",BD:"孟加拉",JP:"日本",KR:"韩国",HK:"香港",ID:"印尼",MY:"马来西亚",PH:"菲律宾",VN:"越南",TH:"泰国",
  SD:"苏丹",EG:"埃及",CD:"刚果民主",ZM:"赞比亚",CI:"科特迪瓦",SA:"沙特",AE:"阿联酋",GH:"加纳",NG:"尼日利亚",KE:"肯尼亚",TZ:"坦桑尼亚",
  ZA:"南非",MA:"摩洛哥",DZ:"阿尔及利亚",TN:"突尼斯",LY:"利比亚",ET:"埃塞俄比亚",UG:"乌干达",RW:"卢旺达",CM:"喀麦隆",SN:"塞内加尔",
  ML:"马里",TG:"多哥",BJ:"贝宁",BF:"布基纳法索",CG:"刚果",GA:"加蓬",ZR:"刚果(金)",LR:"利比里亚",SL:"塞拉利昂",GN:"几内亚",
  IQ:"伊拉克",LB:"黎巴嫩",JO:"约旦",KW:"科威特",QA:"卡塔尔",OM:"阿曼",BH:"巴林",IL:"以色列",SY:"叙利亚",YE:"也门",
  BR:"巴西",AR:"阿根廷",CL:"智利",CO:"哥伦比亚",PE:"秘鲁",MX:"墨西哥",BO:"玻利维亚",VE:"委内瑞拉",EC:"厄瓜多尔",PY:"巴拉圭",
  AU:"澳大利亚",NZ:"新西兰",CA:"加拿大",PL:"波兰",UA:"乌克兰",RO:"罗马尼亚",HU:"匈牙利",CZ:"捷克",SE:"瑞典",DK:"丹麦",
  MD:"摩尔多瓦",PA:"巴拿马",ZW:"津巴布韦",DJ:"吉布提",NP:"尼泊尔",MZ:"莫桑比克",
};
function countryCN(code) { return COUNTRY_CN[code] || code; }

// ═══════════════════════════════════════════════
// 矩阵列定义
// ═══════════════════════════════════════════════
const COLUMNS = [
  { key: "需求探索", label: "需求探索", icon: "🔍" },
  { key: "报价已发", label: "报价已发", icon: "💰" },
  { key: "谈判中",   label: "谈判中",   icon: "🤝" },
  { key: "待付款",   label: "待付款",   icon: "💳" },
  { key: "待发货",   label: "待发货",   icon: "📦" },
  { key: "已发货/在途", label: "在途",  icon: "🚢" },
  { key: "已签收",   label: "已签收",   icon: "✅" },
  { key: "其他",     label: "售后/返单", icon: "🔄" },
];
const COL_KEY_SET = new Set(COLUMNS.map(c => c.key));
function stageColKey(stage) {
  if (COL_KEY_SET.has(stage)) return stage;
  if (stage === "售后" || stage === "待返单") return "其他";
  return "其他";
}

const URGENCY = {
  RED:    { key: "red",    label: "需立即处理", dot: "red",    icon: "🔴", desc: "我不动它就死" },
  YELLOW: { key: "yellow", label: "需定时关注", dot: "yellow", icon: "🟡", desc: "业务推进但需提醒" },
  GREY:   { key: "grey",   label: "正常流转",   dot: "grey",   icon: "⚪", desc: "暂无行动信号" },
  FROZEN: { key: "frozen", label: "冷冻",       dot: "grey",   icon: "❄️", desc: ">90天无互动" },
};

function classifyUrgency(factors) {
  if (!factors || factors.length === 0) return "grey";
  for (const f of factors) {
    const code = (f.factor || "").split("(")[0].trim();
    if (code === "S3 该推进了") return "red";
    if (code === "S4 该催款了" && !f.observeMode) return "red";
  }
  for (const f of factors) {
    if (/^S\d/.test((f.factor || "").split("(")[0].trim())) return "yellow";
  }
  return "grey";
}

// ═══════════════════════════════════════════════
// 驱动因子 → 人类可读描述（v2 品质）
// ═══════════════════════════════════════════════

function buildRichDrivers(factors, stage, daysSince, briefContent) {
  return factors.map(f => {
    const code = (f.factor || "").split("(")[0].trim();
    const days = f.days || daysSince || 0;
    const isObserve = !!f.observeMode;
    const isHigh = f.priority === "high";
    const isDoudi = (f.factor || "").includes("兜底");

    let title = "", detail = "", level = "yellow";

    switch (code) {
      case "S3 该推进了":
        level = "red";
        if (days <= 3) title = `未回复——客户${days}天前发消息等你跟进`;
        else if (days <= 7) title = `该推进——谈判中${days}天客户未回应`;
        else title = `该推进——谈判沉默${days}天，需主动破局`;
        detail = `谈判阶段，客户${days}天前最后回应。节奏第${f.rhythmDay || days}天，该推动下一步决策。`;
        break;

      case "S4 该催款了":
        level = isObserve ? "yellow" : "red";
        if (isObserve) {
          title = `该催款(观察)——PI已发${days}天，长期未付`;
          detail = `待付款${days}天，进入观察模式。如客户有动静再跟进，暂不主动催。`;
        } else {
          title = `该催款——PI已发${days}天等付款`;
          detail = `谈判已完成，PI已发${days}天。客户未付款，该提醒确认付款方式和时间。`;
        }
        break;

      case "S1 该深挖需求了":
        level = "yellow";
        if (isDoudi) title = `该深挖——需求探索超${days}天无实质进展`;
        else if (days <= 7) title = `该深挖需求——${days}天前开始沟通，需了解采购背景`;
        else if (days <= 18) title = `该深挖——沟通${days}天仍停在需求探索`;
        else title = `该深挖——${days}天未推进，需重新激活`;
        detail = `客户在需求探索阶段已停留${days}天。`;
        if (isDoudi) detail += `兜底节奏触发，该主动了解采购规模/目标市场/是否有品牌渠道。`;
        else detail += `节奏第${f.rhythmDay || days}天，该推进到报价或样品阶段。`;
        break;

      case "S2 该追问了":
        level = "yellow";
        title = `该追问——报价后沉默${days}天`;
        detail = `报价已发${days}天，客户未回复也未还价。可能不在采购周期或在比价。温和追问是否收到报价、是否有其他需求。`;
        break;

      case "S5a 该更新进度了":
        level = "yellow";
        if (isHigh) {
          title = `⚠ 该更新进度——超承诺发货日${days}天`;
          detail = `承诺发货日期已过${days}天，必须立即更新客户并给出新时间线。`;
        } else {
          title = `该更新进度——付款后${days}天没给客户更新`;
          detail = `待发货阶段，客户已付款。每${f.interval || 7}天应同步备货/生产进度。该拍照或视频发给客户，给安心感。`;
        }
        break;

      case "S6 该更新物流了":
        level = "yellow";
        title = `物流跟踪——在途${days}天，该同步状态`;
        detail = `货物在途${days}天，每${f.interval || 5}天应跟踪物流并主动通知客户运输进展。到港前3天提醒清关。`;
        break;

      case "S7a 该回访了":
        level = "yellow";
        title = `该回访——签收${days}天未问反馈`;
        detail = `客户已签收${days}天，该回访产品质量满意度和销售情况，同时试探复购意向。`;
        break;

      case "S7b 该推返单了":
        level = "yellow";
        title = `该推返单——签收后进入复购窗口`;
        detail = `签收后${days}天，进入复购窗口。该同步新品、推热卖款，争取返单。`;
        break;

      case "S8 该收尾了":
        level = "yellow";
        title = `该收尾——售后问题${days}天未关闭`;
        detail = `售后问题已开启${days}天，需确认是否已解决。投诉类≤1h响应，常规24h内跟进。`;
        break;

      case "S9 该接触了":
        level = "yellow";
        title = `该接触——待返单客户定期触达`;
        detail = `待返单${days}天，按节奏定期触达。同步新品/行业信息/工厂动态维持存在感。`;
        break;

      default:
        title = f.factor;
        detail = `${days}天前基线(${f.baseline || "?"})`;
    }

    return { level, title, detail, factor: f.factor };
  });
}

// ═══════════════════════════════════════════════
// 芯片徽章（语义化）
// ═══════════════════════════════════════════════

function makeBadge(f, daysSince) {
  const code = (f.factor || "").split("(")[0].trim();
  const days = f.days || daysSince || 0;
  const isObserve = !!f.observeMode;
  const isHigh = f.priority === "high";
  const isDoudi = (f.factor || "").includes("兜底");

  switch (code) {
    case "S3 该推进了":
      if (days <= 3) return `未回${days}d`;
      if (days <= 7) return `沉默${days}d`;
      return `推进${days}d`;
    case "S4 该催款了":
      if (isObserve) return "催款观察";
      return `催款${days}d`;
    case "S1 该深挖需求了":
      if (isDoudi) return `兜底${days}d`;
      return `深挖${days}d`;
    case "S2 该追问了":
      return `追问${days}d`;
    case "S5a 该更新进度了":
      if (isHigh) return "超期!";
      return `进度${days}d`;
    case "S6 该更新物流了":
      return "物流";
    case "S7a 该回访了":
      return "回访";
    case "S7b 该推返单了":
      return "返单";
    case "S8 该收尾了":
      return "收尾";
    case "S9 该接触了":
      return "接触";
    default:
      return "待办";
  }
}

// ═══════════════════════════════════════════════
// 数据加载
// ═══════════════════════════════════════════════

function loadJSON(filename) {
  const p = path.join(OUTPUT_DIR, filename);
  if (!fs.existsSync(p)) return null;
  return JSON.parse(fs.readFileSync(p, "utf-8"));
}

function parseFrontmatter(content) {
  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
  if (!match) return {};
  const fm = {};
  for (const line of match[1].split("\n")) {
    const kv = line.match(/^(\w+):\s*(.+)$/);
    if (kv) fm[kv[1]] = kv[2].trim();
  }
  return fm;
}

function extractSection(content, heading) {
  const re = new RegExp(`## ${heading}\\s*\\n([\\s\\S]*?)(?=\\n## |$)`, "i");
  const m = content.match(re);
  return m ? m[1].trim() : "";
}

/** 从"最近动态"区块提取结构化聊天行 */
function extractChatLines(content) {
  const section = extractSection(content, "最近动态");
  if (!section) return [];
  const lines = [];
  // 格式1: - 2026-05-09 我: hello world（MsgID:xxx）
  // 格式2: - 2026-05-09 我催单：hello world
  // 格式3: [初稿] 最近5条消息摘要：...
  const chatRe = /^-\s*(\d{4}-\d{2}-\d{2})\s+(我|客)(?:催单|告知|跟进|回复|追问|)?[：:]\s*(.+?)(?:（MsgID:[\w.]+）)?$/;
  for (const raw of section.split("\n")) {
    const line = raw.trim();
    if (!line.startsWith("- ")) continue;
    if (line.includes("[初稿]") || line.includes("最近5条消息摘要")) continue;
    const m = line.match(chatRe);
    if (m) {
      lines.push({
        who: m[2] === "我" ? "me" : "cust",
        time: m[1].slice(5), // MM-DD
        text: m[3].trim().substring(0, 150),
      });
    } else {
      // 宽松匹配
      const loose = line.match(/^-\s*(\d{4}-\d{2}-\d{2})\s+(.+)$/);
      if (loose) {
        const rest = loose[2];
        const whoStr = rest.startsWith("我") ? "me" : rest.startsWith("客") ? "cust" : null;
        if (whoStr) {
          const text = rest.replace(/^[我客](?:催单|告知|跟进|回复|追问|)?[：:]?\s*/, "").replace(/（MsgID:[\w.]+）$/, "").trim();
          lines.push({ who: whoStr, time: loose[1].slice(5), text: text.substring(0, 150) });
        }
      }
    }
  }
  return lines.slice(-6); // 最近6条
}

function extractKeyNums(content) {
  const section = extractSection(content, "关键数字");
  if (!section) return [];
  return section.split("\n")
    .filter(l => l.trim().startsWith("-") && !l.includes("[初稿]"))
    .map(l => l.replace(/^-\s*/, "").trim())
    .filter(Boolean);
}

function extractNextStep(content) {
  const section = extractSection(content, "下一步");
  const lines = section.split("\n").filter(l => l.trim().startsWith("→"));
  if (lines.length > 0) {
    return lines.map(l => l.replace(/^→\s*(?:\[初稿\]\s*)?/, "").trim()).join("\n");
  }
  return section.replace(/^→\s*(?:\[初稿\]\s*)?/, "").trim().substring(0, 120);
}

function loadBriefs() {
  const map = {};
  if (!fs.existsSync(BRIEFS_DIR)) return map;
  for (const file of fs.readdirSync(BRIEFS_DIR)) {
    if (!file.endsWith(".md")) continue;
    const content = fs.readFileSync(path.join(BRIEFS_DIR, file), "utf-8");
    const fm = parseFrontmatter(content);
    if (fm.cid) map[fm.cid] = { frontmatter: fm, content, file };
  }
  return map;
}

// ═══════════════════════════════════════════════
// 构建客户卡片
// ═══════════════════════════════════════════════

function buildCustomerCards() {
  const baselines = loadJSON("factor_baselines.json");
  const soon = loadJSON("soon_layer_cards.json");
  const cold = loadJSON("cold_layer_stratification.json");
  const briefs = loadBriefs();

  if (!baselines) {
    console.error("factor_baselines.json 不存在，请先运行 init_factor_baselines.js");
    return null;
  }

  const factorMap = new Map();
  if (soon) for (const c of soon.customers || []) factorMap.set(c.cid, c);

  const coldCids = new Set();
  if (cold) {
    for (const layer of Object.values(cold.frozen || {})) {
      for (const c of layer) coldCids.add(c.cid);
    }
  }

  const cards = [];

  for (const [cid, data] of Object.entries(baselines)) {
    const stage = data.stage || "未知";
    const soonData = factorMap.get(cid);
    const factors = soonData ? soonData.factors : [];
    const urgencyKey = coldCids.has(cid) ? "frozen" : classifyUrgency(factors);
    const tier = (data.meta && data.meta.customer_tier) || "C";

    let daysSince = null, lastContactDate = null, firstContact = null;
    if (data.baselines) {
      let latest = null, earliest = null;
      for (const v of Object.values(data.baselines)) {
        if (v) {
          if (!latest || v > latest) latest = v;
          if (!earliest || v < earliest) earliest = v;
        }
      }
      if (latest) { lastContactDate = latest; daysSince = Math.floor((new Date(TODAY) - new Date(latest)) / 86400000); }
      firstContact = earliest;
    }

    const brief = briefs[cid];
    let chatLines = [], keyNums = [], nextStep = "";

    // 服务端生成富驱动因子描述
    const richDrivers = factors.length > 0
      ? buildRichDrivers(factors, stage, daysSince, brief ? brief.content : null)
      : [];

    if (brief) {
      chatLines = extractChatLines(brief.content);
      keyNums = extractKeyNums(brief.content);
      nextStep = extractNextStep(brief.content);
    }

    cards.push({
      cid,
      name: data.name || "?",
      country: data.country || "?",
      countryCN: countryCN(data.country),
      stage,
      colKey: stageColKey(stage),
      tier,
      urgencyKey,
      factors,
      richDrivers,       // 服务端预生成的驱动因子描述
      daysSince,
      lastContactDate,
      firstContact,
      chatLines,         // 结构化聊天行
      keyNums,
      nextStep,
      hasBrief: !!brief,
      briefFile: brief ? brief.file : null,
    });
  }

  return cards;
}

