function renderHTMLTable(cards) {
  const active = cards.filter(c => c.urgencyKey !== "frozen");

  let html = `<!DOCTYPE html>
<html lang="zh-CN">
<head><meta charset="UTF-8"><title>OKKI 客户看板 — ${TODAY}</title>
<style>
  body { font-family: -apple-system, sans-serif; margin: 20px; color: #333; }
  table { border-collapse: collapse; width: 100%; font-size: 0.9em; }
  th { background: #f5f5f5; padding: 10px 8px; text-align: left; border-bottom: 2px solid #ddd; }
  td { padding: 8px; border-bottom: 1px solid #eee; vertical-align: top; }
  .heat-red { color: #d32f2f; font-weight: bold; }
  .heat-yellow { color: #f57c00; }
  .heat-grey { color: #999; }
  .section-row td { background: #f0f0f0; font-weight: bold; padding: 6px 8px; font-size: 0.85em; }
</style></head><body>
<h1>OKKI 客户看板</h1><p>${TODAY}</p>
<table><thead><tr><th>客户</th><th>国家</th><th>等级</th><th>阶段</th><th>最后联系</th><th>驱动因子</th><th>下一步</th></tr></thead><tbody>`;

  let lastU = "";
  for (const c of active) {
    if (c.urgencyKey !== lastU) {
      lastU = c.urgencyKey;
      html += `<tr class="section-row"><td colspan="7">── ${URGENCY[c.urgencyKey.toUpperCase()]?.label || c.urgencyKey} ──</td></tr>\n`;
    }
    const cls = `heat-${c.urgencyKey}`;
    const factors = c.richDrivers.map(d => d.title).join(" · ") || "—";
    html += `<tr>
  <td>${esc(c.name)}</td><td>${c.countryCN}</td><td>${c.tier}</td><td>${c.stage}</td>
  <td>${c.daysSince !== null ? c.daysSince + "天前" : "?"}</td>
  <td>${esc(factors)}</td><td>${esc((c.nextStep || "—").replace(/\n/g, " "))}</td></tr>\n`;
  }

  html += `</tbody></table></body></html>`;
  return html;
}

function esc(s) {
  if (typeof s !== "string") return String(s);
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
}

// ═══════════════════════════════════════════════
// main
// ═══════════════════════════════════════════════

function main() {
  const cards = buildCustomerCards();
  if (!cards) process.exit(1);

  const counts = {};
  for (const c of cards) counts[c.urgencyKey] = (counts[c.urgencyKey] || 0) + 1;

  let output;
  if (mdMode) {
    output = renderMarkdown(cards);
  } else if (htmlTableMode) {
    output = renderHTMLTable(cards);
  } else {
    output = renderMatrixHTML(cards);
  }

  const dest = outFile || (mdMode || htmlTableMode ? null : path.join(OUTPUT_DIR, "dashboard.html"));

  if (dest) {
    fs.writeFileSync(dest, output, "utf-8");
    console.log(`✅ 看板已生成: ${dest}`);
  } else {
    console.log(output);
  }

  console.error(`\n── OKKI 看板 ${TODAY} ──`);
  console.error(`🔴 需立即处理: ${counts.red || 0}人`);
  console.error(`🟡 需定时关注: ${counts.yellow || 0}人`);
  console.error(`⚪ 正常流转:   ${counts.grey || 0}人`);
  console.error(`❄️ 冷冻:       ${counts.frozen || 0}人`);
  console.error(`📊 总计:       ${cards.length}人`);
}

