  YELLOW: { key: "yellow", label: "需定时关注", dot: "yellow", icon: "🟡", desc: "业务推进但需提醒" },
  GREY:   { key: "grey",   label: "正常流转",   dot: "grey",   icon: "⚪", desc: "暂无行动信号" },
