 * 任务1-4: factor_baselines.json 初始化 + 阶段标签修正 + SOON层建卡 + 冷层/冷冻分层
 *
 * 输入: heat_classification.json (466人)
 * 输出: factor_baselines.json, SOON清单, 冷层/冷冻层清单
 */

const fs = require('fs');
const path = require('path');

const TODAY = '2026-05-18';
const TODAY_DATE = new Date(TODAY);

// ============ 配置 ============

/** 旧阶段 → 新9阶段映射 */
const STAGE_MAP = {
  '需求探索': '需求探索',
  '报价已发': '报价已发',
  '谈判中': '谈判中',
  '待付款': '待付款',
  '待发货': '待发货',
  '已发货/在途': '已发货/在途',
  '已签收': '已签收',
  '售后': '售后',
  '待返单': '待返单',
  // 旧标签映射
  '初询沟通': '需求探索',
  'PI已发': '报价已发',
  '谈判/样品': '谈判中',
  '样品阶段': '谈判中',  // 保守: 未付款→谈判中
  // 未知保持null→冷层
  '未知': null,
};

/** SOON因子节奏表 (V5) */
const RHYTHM = {
  S1:  [1, 2, 3, 5, 7, 9, 15, 30],  // 需求探索 该深挖需求了
  S2:  [1, 3, 5, 15, 30],            // 报价已发 该追问了
  S3:  [1, 3, 5, 7, 15, 30],         // 谈判中 该推进了
  S4:  [1, 3, 5, 7],                  // 待付款 该催款了 (+每7天观察)
  S8:  [1, 2, 3, 5, 7, 15, 30],      // 售后 该收尾了
  S7a: [3, 15, 15, 30, 30, 60],       // 已签收 该回访了 (累计)
  S7b_sample: [7],                     // 样品单 该推返单
  S7b_bulk: [30],                      // 大货 该推返单
  S9_sample: [3, 7, 7, 15, 15, 30, 30],
  S9_bulk:   [7, 15, 15, 30, 30, 60, 60],
};
RHYTHM.S1_MAX = 72;   // 1+2+3+5+7+9+15+30
RHYTHM.S4_MAX = 16;   // 1+3+5+7

/** S5a 双基线间隔计算 */
function s5aInterval(meta) {
  if (meta.customer_type === '样品单') return 3;
  if (!meta.transit_days) return 7; // 默认大货交期35天÷5≈7
  const interval = Math.round(meta.transit_days / 5);
  return Math.max(3, Math.min(10, interval));
}

/** S6 间隔: 时效÷N */
function s6Interval(meta) {
  const transitDays = meta.transit_days || 25;
  const N = { S: 6, A: 6, B: 5, C: 5, D: 4 }[meta.customer_tier] || 5;
  const interval = Math.round(transitDays / N);
  return Math.max(2, Math.min(15, interval));
}

// ============ 辅助函数 ============

function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

function daysBetween(d1, d2) {
  return Math.floor((d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24));
}

/** 判定节奏命中：返回命中的天数索引，未命中返回-1 */
function rhythmHit(days, rhythmArr) {
  // 找到 days 落在哪个间隔的 ±0 容差内 (当天命中)
  for (let i = 0; i < rhythmArr.length; i++) {
    const cumulative = rhythmArr.slice(0, i + 1).reduce((a, b) => a + b, 0);
    if (days === cumulative) return i;
  }
  return -1;
}

/** 获取客户等级 (从 dashboard_snapshot 交叉匹配或默认) */
let tierMap = null;
function loadTierMap() {
  if (tierMap) return tierMap;
  tierMap = new Map();
  try {
    const snap = JSON.parse(fs.readFileSync(
      path.join(__dirname, '..', 'output', '.dashboard_snapshot.json'), 'utf-8'
    ));
    for (const c of snap.customers || []) {
      const key = (c.name || '').toLowerCase() + '|' + (c.country || '');
      tierMap.set(key, c.quality || 'C');
    }
  } catch (e) { /* ignore */ }
  return tierMap;
}

function getTierWithSource(name, country) {
  const map = loadTierMap();
  const key = (name || '').toLowerCase().trim() + '|' + (country || '').toUpperCase().trim();
  const matched = map.get(key);
  if (matched) return { tier: matched, source: 'dashboard_snapshot' };
  return { tier: 'C', source: 'default_C' };
}

/** 加载订单数据 → 客户名→状态查找表 */
function loadOrderMap() {
  const map = new Map();
  try {
    const ordersPath = path.join(__dirname, '..', 'data', 'orders_latest.json');
    if (fs.existsSync(ordersPath)) {
      const orders = JSON.parse(fs.readFileSync(ordersPath, 'utf-8'));
      for (const o of orders.orders || []) {
        const nameKey = (o.customer || '').toLowerCase().trim();
        if (nameKey) map.set(nameKey, o);
      }
    }
  } catch (e) { /* ignore */ }
  return map;
}

/** 用订单数据校正阶段标签 */
function correctStageByOrder(name, currentStage, orderMap) {
  const nameKey = (name || '').toLowerCase().trim();
  const order = orderMap.get(nameKey);
  if (!order) return { stage: currentStage, orderStatus: null, paymentConfirmed: false };

  const st = order.status;
  // 待发货 → 订单状态实际是其他，需要修正
  if (currentStage === '待发货') {
    if (st === '待收款') return { stage: '待付款', orderStatus: st, paymentConfirmed: false };
    if (st === '已发货') return { stage: '已发货/在途', orderStatus: st, paymentConfirmed: true };
    if (st === '交易成功') return { stage: '已签收', orderStatus: st, paymentConfirmed: true };
    if (st === '交易取消') return { stage: '未成交', orderStatus: st, paymentConfirmed: false };
    if (st === '待发货') return { stage: currentStage, orderStatus: st, paymentConfirmed: true };
    return { stage: currentStage, orderStatus: st, paymentConfirmed: false };
  }
  // 待付款 → 实际已发货/已完成
  if (currentStage === '待付款') {
    if (st === '已发货') return { stage: '已发货/在途', orderStatus: st, paymentConfirmed: true };
    if (st === '交易成功') return { stage: '已签收', orderStatus: st, paymentConfirmed: true };
    if (st === '交易取消') return { stage: '未成交', orderStatus: st, paymentConfirmed: false };
    if (st === '待收款') return { stage: currentStage, orderStatus: st, paymentConfirmed: false };
    return { stage: currentStage, orderStatus: st, paymentConfirmed: st === '待发货' };
  }
  // 其他阶段: 仅记录订单状态
  return { stage: currentStage, orderStatus: st, paymentConfirmed: (st === '待发货' || st === '已发货' || st === '交易成功') };
}

/** 判定 target_market 是否非洲/中东 */
function isAfricaOrMiddleEast(country) {
  const africaME = ['SD','EG','CD','ZM','CI','SA','AE','IQ','GH','NG','KE','TZ','UG','ET','CM','SN','ML','BF','BJ','TG','LY','MA','DZ','TN','KW','QA','BH','OM','JO','LB','YE','SY','PS','CG','GA','MR','SO'];
  return africaME.includes((country || '').toUpperCase());
}

