const fs=require('fs');
const d=JSON.parse(fs.readFileSync('output/dashboard.html','utf-8').match(/var CARDS = (\[[\s\S]*?\]);/)[1]);

// Find a customer with paymentConfirmed=false and S5a factor
const s5aNoPay = d.find(c => c.richDrivers.some(dr => dr.title.includes('确认状态')));
console.log('--- Unpaid S5a customer ---');
if (s5aNoPay) {
  const dr = s5aNoPay.richDrivers.find(x => x.title.includes('确认状态'));
  console.log('name:', s5aNoPay.name);
  console.log('title:', dr.title);
  console.log('detail:', dr.detail);
  console.log('paymentConfirmed:', s5aNoPay.paymentConfirmed);
  console.log('badge factor:', s5aNoPay.factors[0]?.factor);
} else { console.log('None found'); }

// Find one with paymentConfirmed=true
const s5aPaid = d.find(c => c.richDrivers.some(dr => dr.title.includes('付款后')));
console.log('\n--- Paid S5a customer ---');
if (s5aPaid) {
  const dr = s5aPaid.richDrivers.find(x => x.title.includes('付款后'));
  console.log('name:', s5aPaid.name);
  console.log('title:', dr.title);
  console.log('detail:', dr.detail);
  console.log('paymentConfirmed:', s5aPaid.paymentConfirmed);
} else { console.log('None found'); }

// Check Becky Nams
const becky = d.find(c => c.name === 'Becky Nams');
console.log('\n--- Becky Nams (corrected to 已发货/在途) ---');
console.log('stage:', becky?.stage, '| factors:', becky?.factors.length, '| paymentConfirmed:', becky?.paymentConfirmed, '| orderStatus:', becky?.orderStatus);
"

