  @keyframes modalIn { from { opacity:0; transform:scale(.96) translateY(8px); } to { opacity:1; transform:scale(1) translateY(0); } }
  .modal-header { padding: 18px 24px; border-bottom: 1px solid #f0f0f0; display: flex; justify-content: space-between; align-items: center; flex-shrink: 0; }
  .modal-header h2 { font-size: 1.15em; }
  .modal-close { background: none; border: none; font-size: 1.4em; cursor: pointer; color: #999; padding: 6px 10px; border-radius: 6px; line-height: 1; }
  .modal-close:hover { background: #f0f0f0; }
  .modal-body { padding: 20px 24px; overflow-y: auto; flex: 1; font-size: 0.88em; line-height: 1.6; }
  .modal-footer { padding: 14px 24px; border-top: 1px solid #f0f0f0; display: flex; gap: 8px; flex-shrink: 0; }

  .btn { padding: 7px 18px; border-radius: 6px; border: 1px solid #ddd; font-size: 0.84em; cursor: pointer; background: #fff; transition: .12s; }
  .btn:hover { background: #f5f5f5; }
  .btn-primary { background: #1976d2; color: #fff; border-color: #1976d2; }
  .btn-primary:hover { background: #1565c0; }

  .fm-grid { display: grid; grid-template-columns: 1fr 1fr 1fr 1fr; gap: 10px; margin-bottom: 18px; }
  .fm-item { background: #fafafa; border-radius: 8px; padding: 10px 14px; }
  .fm-label { color: #999; font-size: 0.7em; text-transform: uppercase; letter-spacing: 0.5px; }
  .fm-value { font-weight: 600; font-size: 0.95em; margin-top: 3px; }

  .section { margin-bottom: 16px; }
  .section-title { font-weight: 600; font-size: 0.8em; color: #888; margin-bottom: 8px; display: flex; align-items: center; gap: 6px; text-transform: uppercase; letter-spacing: 0.5px; }

  .driver-list { display: flex; flex-direction: column; gap: 6px; }
  .driver-item { display: flex; gap: 10px; padding: 10px 14px; border-radius: 8px; font-size: 0.9em; align-items: flex-start; }
  .driver-item-red { background: #fff5f5; border: 1px solid #ffcdd2; }
  .driver-item-yellow { background: #fffdf5; border: 1px solid #ffecb3; }
  .driver-icon { font-size: 1.15em; flex-shrink: 0; margin-top: 1px; }

  .chat-snippet { background: #fafafa; border-radius: 8px; padding: 10px 14px; font-size: 0.86em; }
  .chat-line { padding: 4px 0; display: flex; gap: 10px; align-items: baseline; }
  .chat-who { font-weight: 600; flex-shrink: 0; min-width: 20px; }
  .chat-who-me { color: #1976d2; }
  .chat-who-cust { color: #d32f2f; }
  .chat-time { color: #bbb; font-size: 0.78em; flex-shrink: 0; min-width: 45px; }

  .key-num { background: #f5f5f5; border-radius: 6px; padding: 7px 12px; margin-bottom: 4px; font-size: 0.85em; }
  .info-note { background: #fff9c4; border-radius: 6px; padding: 8px 12px; font-size: 0.82em; color: #666; }

  .frozen-row { background: #fafafa; padding: 8px 14px; font-size: 0.74em; color: #999; display: flex; flex-wrap: wrap; gap: 4px; align-items: center; }
  .frozen-chip { cursor: default; opacity: 0.5; }
  .frozen-chip:hover { transform: none; box-shadow: none; }

  .legend { font-size: 0.75em; color: #999; margin-top: 14px; display: flex; gap: 20px; flex-wrap: wrap; }
</style>
</head>
<body>

<h1>OKKI 客户状态看板</h1>
<p class="subtitle">横轴：生命周期阶段 → ｜ 纵轴：紧急度 ｜ 点击客户卡片查看详情 ｜ ${now}</p>

<div class="summary-bar">
  <span>🔴 需立即处理 <strong>${counts.red || 0}</strong></span>
  <span>🟡 需定时关注 <strong>${counts.yellow || 0}</strong></span>
  <span>⚪ 正常流转 <strong>${counts.grey || 0}</strong></span>
  <span>❄️ 冷冻 <strong>${counts.frozen || 0}</strong></span>
</div>

<div class="matrix-wrap">
<div class="matrix" style="grid-template-columns: 80px repeat(${COLUMNS.length}, 1fr);">
  <div class="cell-header"></div>
${COLUMNS.map(col => `  <div class="cell-header">${col.icon} ${col.label}</div>`).join("\n")}
`;

  for (const u of [URGENCY.RED, URGENCY.YELLOW, URGENCY.GREY, URGENCY.FROZEN]) {
    const dotClass = `chip-dot-${u.dot}`;
    const opacity = u.key === "frozen" ? ' style="opacity:0.45"' : "";

    if (u.key === "frozen") {
      const show = frozenList.slice(0, 10);
      const rest = frozenList.length - 10;
      const chips = show.map(c => `<span class="customer-chip chip-grey frozen-chip">${esc(c.name)}</span>`).join("\n    ");
      const more = rest > 0 ? `<span class="customer-chip chip-grey frozen-chip">+${rest}人</span>` : "";
      html += `  <div class="row-label"${opacity}><span class="chip-dot ${dotClass}"></span>${u.icon} ${u.label}</div>\n`;
      html += `  <div class="frozen-row" style="grid-column: span ${COLUMNS.length};">${chips}${more}</div>\n`;
      continue;
    }

    html += `  <div class="row-label"${opacity}><span class="chip-dot ${dotClass}"></span>${u.icon} ${u.label}</div>\n`;

    for (const col of COLUMNS) {
      const bucket = matrix[u.key][col.key] || [];
      if (bucket.length === 0) {
        html += `  <div class="cell"></div>\n`;
        continue;
      }

      if (u.key === "grey") {
        // 正常流转：展示更多芯片，超过20个才折叠
        const maxShow = 20;
        const show = bucket.slice(0, maxShow);
        const rest = bucket.length - maxShow;
        const chips = show.map(c =>
          `<span class="customer-chip chip-grey" onclick="openModal('${esc(c.cid)}')">${esc(c.name)}</span>`
        ).join("");
        const more = rest > 0 ? `<span class="customer-chip chip-grey">+${rest}</span>` : "";
        html += `  <div class="cell">${chips}${more}</div>\n`;
      } else {
        const chipClass = u.key === "red" ? "chip-red" : "chip-yellow";
        const chips = bucket.map(c => {
          const badge = c.factors.length > 0 ? makeBadge(c.factors[0], c.daysSince, c.paymentConfirmed) : "";
          const tierMark = (c.tier === "S" || c.tier === "A")
            ? `<span class="chip-tier-${c.tier.toLowerCase()}">${c.tier}</span>` : "";
          return `<span class="customer-chip ${chipClass}" onclick="openModal('${esc(c.cid)}')"><span class="chip-dot ${dotClass}"></span>${esc(c.name)}${tierMark}<span class="chip-badge">${badge}</span></span>`;
        }).join("\n    ");
        html += `  <div class="cell">${chips}</div>\n`;
      }
    }
  }

  html += `</div>
</div>

<div class="legend">
  <span>🔴 需立即处理 = ${URGENCY.RED.desc}</span>
  <span>🟡 需定时关注 = ${URGENCY.YELLOW.desc}</span>
  <span>⚪ 正常流转 = ${URGENCY.GREY.desc}</span>
  <span>❄️ 冷冻 = ${URGENCY.FROZEN.desc}</span>
</div>

<div class="overlay" id="overlay" onclick="if(event.target===this)closeModal()">
<div class="modal" id="modal"></div>
</div>

<script>
var CARDS = ${JSON.stringify(cards)};

function openModal(cid) {
  var c = CARDS.find(function(x){ return x.cid === cid; });
  if (!c) return;
  var h = '';
  h += '<div class="modal-header"><h2>' + esc(c.name) + '</h2><button class="modal-close" onclick="closeModal()">✕</button></div>';
  h += '<div class="modal-body">';

  // Frontmatter
  h += '<div class="fm-grid">';
  var fields = [
    ['国家', c.countryCN || c.country],
    ['阶段', c.stage],
    ['等级', c.tier + '级'],
    ['最后联系', c.daysSince !== null ? c.daysSince + '天前' : '?']
  ];
  for (var i = 0; i < fields.length; i++) {
    h += '<div class="fm-item"><div class="fm-label">' + fields[i][0] + '</div><div class="fm-value">' + esc(String(fields[i][1])) + '</div></div>';
  }
  if (c.firstContact) {
    h += '<div class="fm-item"><div class="fm-label">首次联系</div><div class="fm-value">' + c.firstContact + '</div></div>';
  }
  h += '</div>';

  // Driver factors (服务端预生成)
  if (c.richDrivers && c.richDrivers.length) {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="driver-list">';
    for (var j = 0; j < c.richDrivers.length; j++) {
      var dr = c.richDrivers[j];
      var cls = dr.level === 'red' ? 'driver-item-red' : 'driver-item-yellow';
      var icon = dr.level === 'red' ? '🔴' : '🟡';
      h += '<div class="driver-item ' + cls + '"><span class="driver-icon">' + icon + '</span><div><strong>' + esc(dr.title) + '</strong><div style="color:#999;font-size:0.85em;margin-top:2px;">' + esc(dr.detail) + '</div></div></div>';
    }
    h += '</div></div>';
  } else if (c.urgencyKey === 'red') {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">⚠️ 该客户标记为需立即处理（状态卡热度=NOW），但未命中因子节奏天。请检查状态卡确认紧急原因。</div></div>';
  } else if (c.urgencyKey === 'yellow') {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">📌 该客户标记为需关注（状态卡热度=NOW/SOON），但未命中因子节奏天。可能是刚联系过或等待客户行动中。</div></div>';
  } else if (c.urgencyKey !== 'frozen') {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">无活跃因子。该客户在正常流转中，暂无行动信号。</div></div>';
  }

  // Chat lines (结构化)
  if (c.chatLines && c.chatLines.length) {
