1	#!/usr/bin/env node
2	/**
3	 * gen_dashboard.js — OKKI 矩阵看板 + 弹窗详情（v2 品质）
4	 *
5	 * 数据源:
6	 *   - output/factor_baselines.json   (全员阶段+基线+等级)
7	 *   - output/soon_layer_cards.json   (SOON 因子命中清单)
8	 *   - output/cold_layer_stratification.json (冷层/冷冻分层)
9	 *   - data/briefs/*.md              (状态卡，聊天/关键数字/下一步)
10	 *
11	 * 用法:
12	 *   node scripts/gen_dashboard.js                  → 矩阵 HTML → output/dashboard.html
13	 *   node scripts/gen_dashboard.js --md              → Markdown 表格 → stdout
14	 *   node scripts/gen_dashboard.js --html            → 旧版 HTML 表格 → stdout
15	 *   node scripts/gen_dashboard.js -o board.html     → 指定输出路径
16	 */
17	
18	const fs = require("fs");
19	const path = require("path");
20	
21	const ROOT = path.resolve(__dirname, "..");
22	const OUTPUT_DIR = path.join(ROOT, "output");
23	const BRIEFS_DIR = path.join(ROOT, "data", "briefs");
24	const TODAY = new Date().toISOString().slice(0, 10);
25	
26	const args = process.argv.slice(2);
27	const mdMode = args.includes("--md");
28	const htmlTableMode = args.includes("--html");
29	const outFile = (() => {
30	  const idx = args.indexOf("-o");
31	  return idx >= 0 ? args[idx + 1] : null;
32	})();
33	
34	// ═══════════════════════════════════════════════
35	// 国家代码 → 中文
36	// ═══════════════════════════════════════════════
37	const COUNTRY_CN = {
38	  US:"美国",GB:"英国",DE:"德国",FR:"法国",IT:"意大利",ES:"西班牙",NL:"荷兰",BE:"比利时",PT:"葡萄牙",RU:"俄罗斯",TR:"土耳其",
39	  IN:"印度",PK:"巴基斯坦",BD:"孟加拉",JP:"日本",KR:"韩国",HK:"香港",ID:"印尼",MY:"马来西亚",PH:"菲律宾",VN:"越南",TH:"泰国",
40	  SD:"苏丹",EG:"埃及",CD:"刚果民主",ZM:"赞比亚",CI:"科特迪瓦",SA:"沙特",AE:"阿联酋",GH:"加纳",NG:"尼日利亚",KE:"肯尼亚",TZ:"坦桑尼亚",
41	  ZA:"南非",MA:"摩洛哥",DZ:"阿尔及利亚",TN:"突尼斯",LY:"利比亚",ET:"埃塞俄比亚",UG:"乌干达",RW:"卢旺达",CM:"喀麦隆",SN:"塞内加尔",
42	  ML:"马里",TG:"多哥",BJ:"贝宁",BF:"布基纳法索",CG:"刚果",GA:"加蓬",ZR:"刚果(金)",LR:"利比里亚",SL:"塞拉利昂",GN:"几内亚",
43	  IQ:"伊拉克",LB:"黎巴嫩",JO:"约旦",KW:"科威特",QA:"卡塔尔",OM:"阿曼",BH:"巴林",IL:"以色列",SY:"叙利亚",YE:"也门",
44	  BR:"巴西",AR:"阿根廷",CL:"智利",CO:"哥伦比亚",PE:"秘鲁",MX:"墨西哥",BO:"玻利维亚",VE:"委内瑞拉",EC:"厄瓜多尔",PY:"巴拉圭",
45	  AU:"澳大利亚",NZ:"新西兰",CA:"加拿大",PL:"波兰",UA:"乌克兰",RO:"罗马尼亚",HU:"匈牙利",CZ:"捷克",SE:"瑞典",DK:"丹麦",
46	  MD:"摩尔多瓦",PA:"巴拿马",ZW:"津巴布韦",DJ:"吉布提",NP:"尼泊尔",MZ:"莫桑比克",
47	};
48	function countryCN(code) { return COUNTRY_CN[code] || code; }
49	
50	// ═══════════════════════════════════════════════
51	// 矩阵列定义
52	// ═══════════════════════════════════════════════
53	const COLUMNS = [
54	  { key: "需求探索", label: "需求探索", icon: "🔍" },
55	  { key: "报价已发", label: "报价已发", icon: "💰" },
56	  { key: "谈判中",   label: "谈判中",   icon: "🤝" },
57	  { key: "待付款",   label: "待付款",   icon: "💳" },
58	  { key: "待发货",   label: "待发货",   icon: "📦" },
59	  { key: "已发货/在途", label: "在途",  icon: "🚢" },
60	  { key: "已签收",   label: "已签收",   icon: "✅" },
61	  { key: "其他",     label: "售后/返单", icon: "🔄" },
62	];
63	const COL_KEY_SET = new Set(COLUMNS.map(c => c.key));
64	function stageColKey(stage) {
65	  if (COL_KEY_SET.has(stage)) return stage;
66	  if (stage === "售后" || stage === "待返单") return "其他";
67	  return "其他";
68	}
69	
70	const URGENCY = {
71	  RED:    { key: "red",    label: "需立即处理", dot: "red",    icon: "🔴", desc: "我不动它就死" },
72	  YELLOW: { key: "yellow", label: "需定时关注", dot: "yellow", icon: "🟡", desc: "业务推进但需提醒" },
73	  GREY:   { key: "grey",   label: "正常流转",   dot: "grey",   icon: "⚪", desc: "暂无行动信号" },
74	  FROZEN: { key: "frozen", label: "冷冻",       dot: "grey",   icon: "❄️", desc: ">90天无互动" },
75	};
76	
77	function classifyUrgency(factors, briefHeat) {
78	  if (!factors || factors.length === 0) {
79	    // 无因子时用 brief heat 做基准，但不直接进 RED（避免 stale brief 过度告警）
80	    if (briefHeat === "NOW") return "yellow";
81	    if (briefHeat === "SOON") return "yellow";
82	    return "grey";
83	  }
84	  for (const f of factors) {
85	    const code = (f.factor || "").split("(")[0].trim();
86	    if (code === "S3 该推进了") return "red";
87	    if (code === "S4 该催款了" && !f.observeMode) return "red";
88	  }
89	  for (const f of factors) {
90	    if (/^S\d/.test((f.factor || "").split("(")[0].trim())) return "yellow";
91	  }
92	  // 有因子但非 S1-S9：用 brief heat
93	  if (briefHeat === "NOW" || briefHeat === "SOON") return "yellow";
94	  return "grey";
95	}
96	
97	// ═══════════════════════════════════════════════
98	// 驱动因子 → 人类可读描述（v2 品质）
99	// ═══════════════════════════════════════════════
100	
101	function buildRichDrivers(factors, stage, daysSince, paymentConfirmed, briefContent) {
102	  return factors.map(f => {
103	    const code = (f.factor || "").split("(")[0].trim();
104	    const days = f.days || daysSince || 0;
105	    const isObserve = !!f.observeMode;
106	    const isHigh = f.priority === "high";
107	    const isDoudi = (f.factor || "").includes("兜底");
108	
109	    let title = "", detail = "", level = "yellow";
110	
111	    switch (code) {
112	      case "S3 该推进了":
113	        level = "red";
114	        if (days <= 3) title = `未回复——客户${days}天前发消息等你跟进`;
115	        else if (days <= 7) title = `该推进——谈判中${days}天客户未回应`;
116	        else title = `该推进——谈判沉默${days}天，需主动破局`;
117	        detail = `谈判阶段，客户${days}天前最后回应。节奏第${f.rhythmDay || days}天，该推动下一步决策。`;
118	        break;
119	
120	      case "S4 该催款了":
121	        level = isObserve ? "yellow" : "red";
122	        if (isObserve) {
123	          title = `该催款(观察)——PI已发${days}天，长期未付`;
124	          detail = `待付款${days}天，进入观察模式。如客户有动静再跟进，暂不主动催。`;
125	        } else if (f.overdue) {
126	          title = `该催款——第${f.rhythmDay}天节点已过，已${days}天未付款`;
127	          detail = `第${f.rhythmDay}天节点应跟进，现已${days}天仍未付。前面节点没跟的话现在就该行动。`;
128	        } else {
129	          title = `该催款——PI已发${days}天等付款`;
130	          detail = `谈判已完成，PI已发${days}天。客户未付款，该提醒确认付款方式和时间。`;
131	        }
132	        break;
133	
