        if (f.degraded) {
          level = "yellow";
          title = \`该催款——已过15天，客户可能无付款意愿\`;
          detail = \`第1/3/5/7/15天节点均已过，当前第\${days}天未付。建议不再每日提醒，降级为定期观察。\`;
        } else {
          level = "red";
          if (f.overdue) {
            title = \`该催款——第1/3/5/7天节点已过，已\${days}天未提醒付款\`;
            detail = \`按节奏应在第1/3/5/7/15天提醒，前面均错过。现在第\${days}天，该补上催款。\`;
          } else {
            title = \`该催款——PI已发\${days}天等付款\`;
            detail = \`谈判已完成，PI已发\${days}天。客户未付款，该提醒确认付款方式和时间。\`;
          }
        }
        break;`;

if (c.includes(oldBuild)) {
  c = c.replace(oldBuild, newBuild);
  console.log('buildRichDrivers: S4 degraded added');
} else console.log('ERROR: buildRichDrivers block not found');

// 2. S4 badge: add degraded
const oldBadge = `    case "S4 该催款了":
      if (isObserve) return "催款观察";
      return \`催款\${days}d\`;`;

const newBadge = `    case "S4 该催款了":
      if (isObserve) return "催款观察";
      if (f.degraded) return "降级";
      if (f.overdue) return \`补催\${days}d\`;
      return \`催款\${days}d\`;`;

if (c.includes(oldBadge)) {
  c = c.replace(oldBadge, newBadge);
  console.log('badge: S4 degraded added');
} else console.log('ERROR: badge block not found');

